/**
 * Study AM corpus (docs/BRIEF-AM.md): 40 cap-edge (K=20) integrity
 * tasks for the consolidation-on-notice study, generated by the Study
 * AH machinery over the size-extension trees. memo-scale.json is
 * untouched (content-hash pinned by AK/AL). Committed as
 * corpus/memo-consolidation.json before any scored AM call.
 */
import { mkdirSync, readFileSync, writeFileSync } from "node:fs";
import type { IntegrityTask } from "../src/corpus/memoscale.js";
import {
	tryIntegrityTask,
	validateIntegrityTask,
} from "../src/corpus/memoscale.js";
import { createRng } from "../src/corpus/rng.js";
import type { Corpus, TransformationTask } from "../src/corpus/tasks.js";

/** Pre-registered Study AM seed (BRIEF-AM.md). */
export const CONSOLIDATION_SEED = 20260719;

const REPS = 40;

const source = JSON.parse(
	readFileSync("corpus/size-extension.json", "utf8"),
) as Corpus;
const trees = source.tasks as TransformationTask[];

const integrity: IntegrityTask[] = [];
let cellSeq = 0;

for (let rep = 1; rep <= REPS; rep += 1) {
	let made: IntegrityTask | null = null;
	for (let offset = 0; offset < trees.length && !made; offset += 1) {
		const tree = trees[(cellSeq + offset) % trees.length] as TransformationTask;
		made = tryIntegrityTask(
			tree.tree,
			createRng(CONSOLIDATION_SEED + cellSeq * 977 + offset * 13 + 500_000),
			20,
		);
		if (made) made.bucket = tree.bucket;
	}
	if (!made) throw new Error(`no tree yields integrity k20 rep${rep}`);
	cellSeq += 1;
	made.id = `am-consolidation-${rep}`;
	const problems = validateIntegrityTask(made);
	if (problems.length > 0) {
		throw new Error(`corpus bug ${made.id}: ${problems.join("; ")}`);
	}
	integrity.push(made);
}

const corpus = { version: 1 as const, seed: CONSOLIDATION_SEED, integrity };
mkdirSync("corpus", { recursive: true });
writeFileSync(
	"corpus/memo-consolidation.json",
	`${JSON.stringify(corpus, null, "\t")}\n`,
);
console.log(
	`corpus/memo-consolidation.json — ${integrity.length} cap-edge integrity tasks, all validated`,
);
console.log(`  ${integrity[0]?.id}: ${integrity[0]?.message.slice(0, 110)}`);
